package org.apache.commons.codec.binary;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/org/apache/commons/codec/binary/requirement.feature",
    glue = "org.apache.commons.codec.binary.steps",
    plugin = {"pretty", "html:target/cucumber-reports.html"}
)
public class CucumberTest {
}

package org.apache.commons.codec.binary.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.apache.commons.codec.binary.StringUtils;
import static org.junit.Assert.assertNull;

public class StepDefs {

    private String result;

    @Given("the StringUtils class is available")
    public void the_StringUtils_class_is_available() {
        // Class is available
    }

    @When("I decode a null byte array using ISO-8859-1")
    public void i_decode_a_null_byte_array_using_ISO_8859_1() {
        try {
            result = StringUtils.newStringIso8859_1(null);
        } catch (Exception e) {
            result = "EXCEPTION"; 
        }
    }

    @When("I decode a null byte array using UTF-8")
    public void i_decode_a_null_byte_array_using_UTF_8() {
        try {
            result = StringUtils.newStringUtf8(null);
        } catch (Exception e) {
             result = "EXCEPTION";
        }
    }

    @When("I decode a null byte array using US-ASCII")
    public void i_decode_a_null_byte_array_using_US_ASCII() {
        try {
            result = StringUtils.newStringUsAscii(null);
        } catch (Exception e) {
            result = "EXCEPTION";
        }
    }

    @When("I decode a null byte array using UTF-16")
    public void i_decode_a_null_byte_array_using_UTF_16() {
        try {
            result = StringUtils.newStringUtf16(null);
        } catch (Exception e) {
            result = "EXCEPTION";
        }
    }

    @When("I decode a null byte array using UTF-16BE")
    public void i_decode_a_null_byte_array_using_UTF_16BE() {
        try {
            result = StringUtils.newStringUtf16Be(null);
        } catch (Exception e) {
            result = "EXCEPTION";
        }
    }

    @When("I decode a null byte array using UTF-16LE")
    public void i_decode_a_null_byte_array_using_UTF_16LE() {
        try {
            result = StringUtils.newStringUtf16Le(null);
        } catch (Exception e) {
            result = "EXCEPTION";
        }
    }

    @Then("the result should be null")
    public void the_result_should_be_null() {
        assertNull("Result should be null but was: " + result, result);
    }
}
